mapper.select:
SELECT EXAM_CD examCd, EXAM_NM examNm, ISUSE isUse FROM exam_mst WHERE 1=1
AND EXAM_NM LIKE '%' #{searchKeyword} '%'
LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

        SELECT EXAM_CD examCd, EXAM_NM examNm, ISUSE isUse
		FROM exam_mst
		WHERE EXAM_CD = #{examCd}

mapper.insert:
INSERT INTO exam_mst (
	EXAM_NM, ISUSE
) VALUES (
	#{examNm}, #{isUse}
)

mapper.update:
UPDATE exam_mst
SET 
	EXAM_NM = #{examNm},
	ISUSE = #{isUse}
WHERE EXAM_CD = #{examCd}

